"""Базовый провайдер документа: supported_extensions и extract."""from __future__ import annotationsimport threadingfrom abc import ABC, abstractmethodfrom typing import TYPE_CHECKING, Anyfrom ..models import ExtractedDocumentfrom src.modules.settings_schema.models import SettingFieldSchemaif TYPE_CHECKING:    from ..services.file_extract_cache import FileExtractCacheService    from ..models import ExtractConfig, SourceDocumentclass FileExtractProvider(ABC):    """Базовый класс провайдера извлечения контента из документа."""    PROVIDER_CODE: str = ""    PROVIDER_TITLE: str = ""    PROVIDER_DESCRIPTION: str = ""    @classmethod    def provider_code(cls) -> str:        """Код провайдера (snake_case). Берётся из константы PROVIDER_CODE класса-наследника."""        return cls.PROVIDER_CODE    @classmethod    def provider_title(cls) -> str:        """Код провайдера для привязки к локализации (GUI: project_extract.provider.<code>.title)."""        return cls.PROVIDER_CODE    @classmethod    def provider_description(cls) -> str:        """Описание группы для UI; пусто — подписи только у полей схемы."""        return cls.PROVIDER_DESCRIPTION    def get_setting(self, config: "ExtractConfig", key: str, default: Any = None) -> Any:        """Значение настройки провайдера по ключу из схемы (без передачи provider_code)."""        return config.get_provider_value(type(self).provider_code(), key, default)    @staticmethod    @abstractmethod    def supported_extensions() -> set[str]:        """Возвращает множество поддерживаемых расширений (нижний регистр, с точкой)."""        ...    @classmethod    @abstractmethod    def project_settings_schema(cls) -> tuple[SettingFieldSchema, ...]:        """Схема полей: label = key (код), description пустой; select — пары (код значения, код опции). Локализация в GUI."""        ...    @abstractmethod    def extract(        self,        source: "SourceDocument",        config: "ExtractConfig",        storage: "FileExtractCacheService",        document_hash: str,        cancel_event: threading.Event | None = None,    ) -> ExtractedDocument:        """Извлекает контент из документа; при необходимости сохраняет артефакты через storage."""        ...